  post_title = 'DigiWin Header v5',
  post_content = '<!-- wp:divi/placeholder -->\n<!-- wp:html --><style>/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n\n\n/* === TB BODY WRAPPER RESET (must be last — specificity 0,4,0 beats all :has() rules at 0,3,0) === */\n.et-l--body .et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et-l--body .et_pb_row[class*="tb_body"]{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et-l--body .et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Header"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{position:fixed !important;top:0 !important;left:0 !important;right:0 !important;z-index:999999 !important;padding:0 !important;margin:0 !important;background:transparent !important;width:100% !important;max-width:100% !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Header Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Header Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{padding:0 !important;}"}}}} -->\n<!-- wp:divi/code {"content":{"innerContent":{"desktop":{"value":"<!-- Google Tag Manager -->\\n<script>(function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({\'gtm.start\':\\nnew Date().getTime(),event:\'gtm.js\'});var f=d.getElementsByTagName(s)[0],\\nj=d.createElement(s),dl=l!=\'dataLayer\'?\'&l=\'+l:\'\';j.async=true;j.src=\\n\'https://www.googletagmanager.com/gtm.js?id=\'+i+dl;f.parentNode.insertBefore(j,f);\\n})(window,document,\'script\',\'dataLayer\',\'GTM-M83NQFRQ\');</script>\\n<!-- End Google Tag Manager -->\\n<!-- Google Tag Manager (noscript) -->\\n<noscript><iframe src=\\"https://www.googletagmanager.com/ns.html?id=GTM-M83NQFRQ\\"\\nheight=\\"0\\" width=\\"0\\" style=\\"display:none;visibility:hidden\\"></iframe></noscript>\\n<!-- End Google Tag Manager (noscript) -->\\n<link rel=\\"preconnect\\" href=\\"https://fonts.googleapis.com\\">\\n<link rel=\\"preconnect\\" href=\\"https://fonts.gstatic.com\\" crossorigin>\\n<link href=\\"https://fonts.googleapis.com/css2?family=Noto+Sans+Thai:wght@400;500;600;700&display=swap\\" rel=\\"stylesheet\\">\\n<style>\\n\\n/* ===== HEADER ===== */\\n/* Divi section wrapper: override overflow:hidden so mega-menu dropdowns are visible */\\n.et_pb_section.et_pb_section_0_tb_header{overflow:visible !important}\\n/* Reset Divi\'s inherited line-height (23.8px from 1.49em×16px) and <p> padding on all header elements */\\n.dw-header,.dw-header *{line-height:1.6;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\\n.dw-header p,.dw-header h1,.dw-header h2,.dw-header h3{margin:0;padding:0}\\n.dw-header{background:rgba(255,255,255,0.95);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);box-shadow:0 1px 0 rgba(37,59,80,0.08);position:fixed;top:0;left:0;right:0;z-index:999999;transition:all 0.3s ease}\\n.dw-header.scrolled{box-shadow:0 4px 30px rgba(37,59,80,0.12)}\\n.dw-header-inner{max-width:1400px;margin:0 auto;display:flex;align-items:center;justify-content:space-between;padding:0 40px;height:80px}\\n\\n/* Logo */\\n.dw-logo{display:flex;flex-wrap:wrap;align-items:center;text-decoration:none;transition:transform 0.3s ease;gap:0}\\n.dw-logo:hover{transform:scale(1.02)}\\n.dw-logo-img{height:auto;display:block}\\n.dw-logo-img--desktop{width:160px;display:block}\\n.dw-logo-img--mobile{width:32px;display:none}\\n.dw-logo-since{display:block;width:100%;font-family:\'Noto Sans\', sans-serif;font-size:10px;font-weight:400;letter-spacing:0.12em;color:#0284c7;margin-top:2px;transition:color 0.3s ease}\\n.dw-logo:hover .dw-logo-since{color:#00AFF0}\\n\\n/* Nav */\\n.dw-nav{display:flex;align-items:center;gap:8px;position:relative;top:auto;left:auto;width:auto;height:auto;background:transparent;flex-direction:row;overflow-y:visible;padding:0;z-index:auto;box-shadow:none}\\n.dw-nav-item{position:relative;width:auto;border-bottom:none}\\n.dw-nav-link{font-family:\'Noto Sans\', sans-serif;font-size:16px;font-weight:500;color:#000864;text-decoration:none;padding:20px 24px;display:flex;align-items:center;gap:6px;transition:all 0.3s ease;cursor:pointer;position:relative;justify-content:flex-start;width:auto}\\n.dw-nav-link::after{content:\'\';position:absolute;bottom:20px;left:20px;right:20px;height:2px;background:linear-gradient(90deg, #00AFF0, #0ea5e9);border-radius:2px;transform:scaleX(0);transition:transform 0.3s cubic-bezier(0.4, 0, 0.2, 1)}\\n.dw-nav-link:hover{color:#0284c7}\\n.dw-nav-link:hover::after{transform:scaleX(1)}\\n.dw-nav-item.active .dw-nav-link::after{transform:scaleX(1)}\\n.dw-nav-link svg{width:14px;height:14px;transition:transform 0.3s ease;stroke-width:2.5}\\n.dw-nav-item.active .dw-nav-link svg,.dw-nav-item:hover .dw-nav-link svg{transform:rotate(180deg)}\\n\\n/* Mega menu */\\n.dw-mega-menu{position:fixed;top:80px;left:0;right:0;background:#ffffff;box-shadow:0 20px 60px rgba(37,59,80,0.15), 0 0 0 1px rgba(37,59,80,0.05);z-index:999998;opacity:0;visibility:hidden;transform:translateY(-10px);transition:all 0.3s cubic-bezier(0.4, 0, 0.2, 1);display:block;padding:0;width:auto;border-radius:0}\\n.dw-mega-menu.active{opacity:1;visibility:visible;transform:translateY(0)}\\n.dw-mega-menu::before{content:\'\';position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg, #00AFF0, #0ea5e9, #06b6d4)}\\n.dw-mega-inner{max-width:1400px;margin:0 auto;padding:40px;display:grid;grid-template-columns:1fr 1fr 380px;gap:40px}\\n.dw-mega-column{display:flex;flex-direction:column;gap:4px}\\n.dw-mega-column-title{font-family:\'Noto Sans\', sans-serif;font-size:12px;font-weight:600;color:#5b6b80;text-transform:uppercase;letter-spacing:0.1em;padding:0 16px 12px;margin-bottom:8px;border-bottom:1px solid #f1f5f9}\\n.dw-mega-item{display:flex;align-items:center;gap:14px;padding:12px 16px;border-radius:10px;text-decoration:none;transition:all 0.2s ease}\\n.dw-mega-item:hover{background:#f8fafc}\\n.dw-mega-item:hover .dw-mega-icon{background:linear-gradient(135deg, #00AFF0 0%, #0284c7 100%)}\\n.dw-mega-item:hover .dw-mega-icon svg{stroke:#ffffff}\\n.dw-mega-item:hover .dw-mega-title{color:#0284c7}\\n.dw-mega-icon{width:36px;height:36px;min-width:36px;background:#f1f5f9;border-radius:8px;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:all 0.2s ease}\\n.dw-mega-icon svg{width:20px;height:20px;stroke:#5b6b80;stroke-width:1.5;fill:none;transition:all 0.2s ease}\\n.dw-mega-info{flex:1;min-width:0}\\n.dw-mega-title{font-family:\'Noto Sans\', sans-serif;font-size:15px;font-weight:500;color:#000864;margin:0;transition:color 0.2s ease}\\n.dw-mega-desc{font-family:\'Noto Sans\', sans-serif;font-size:13px;color:#5b6b80;margin:2px 0 0;line-height:1.3}\\n\\n/* Featured panel */\\n.dw-mega-featured{background:linear-gradient(145deg,#f8fafc 0%,#f1f5f9 100%);border-radius:16px;overflow:hidden;display:flex;flex-direction:column}\\n.dw-mega-featured-image{height:180px;background:linear-gradient(135deg, #000864 0%, #1e3a5f 50%, #0f172a 100%);position:relative;overflow:hidden;display:flex;align-items:center;justify-content:center}\\n.dw-mega-featured-image::before{content:\'\';position:absolute;top:0;right:0;width:70%;height:100%;background:radial-gradient(ellipse at right,rgba(0,175,240,0.3) 0%,transparent 70%)}\\n.dw-mega-featured-image svg{width:100px;height:100px;stroke:rgba(0,175,240,0.4);stroke-width:1;fill:none;position:relative;z-index:1}\\n.dw-mega-featured-content{padding:24px;flex:1;display:flex;flex-direction:column}\\n.dw-mega-featured-label{font-family:\'JetBrains Mono\', monospace;font-size:10px;font-weight:500;color:#0284c7;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:8px}\\n.dw-mega-featured-title{font-family:\'Noto Sans\', sans-serif;font-size:18px;font-weight:700;color:#000864;margin:0 0 8px;line-height:1.3}\\n.dw-mega-featured-desc{font-family:\'Noto Sans\', sans-serif;font-size:14px;color:#5b6b80;margin:0 0 20px;line-height:1.5;flex:1}\\n.dw-mega-featured-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\', sans-serif;font-size:14px;font-weight:600;color:#ffffff;background:linear-gradient(135deg, #00AFF0 0%, #0284c7 100%);padding:12px 20px;border-radius:8px;text-decoration:none;transition:all 0.3s ease;align-self:flex-start}\\n.dw-mega-featured-cta:hover{transform:translateY(-2px);box-shadow:0 6px 20px rgba(0,175,240,0.35)}\\n.dw-mega-featured-cta svg{width:16px;height:16px;stroke:currentColor;stroke-width:2;fill:none;transition:transform 0.2s ease}\\n.dw-mega-featured-cta:hover svg{transform:translateX(3px)}\\n.dw-mega-viewall{display:flex;align-items:center;gap:8px;font-family:\'Noto Sans\', sans-serif;font-size:14px;font-weight:600;color:#0284c7;padding:16px;margin-top:auto;text-decoration:none;transition:all 0.2s ease;border-top:1px solid #e2e8f0}\\n.dw-mega-viewall:hover{color:#0284c7;background:#f8fafc}\\n.dw-mega-viewall svg{width:16px;height:16px;stroke:currentColor;stroke-width:2;fill:none;transition:transform 0.2s ease}\\n.dw-mega-viewall:hover svg{transform:translateX(4px)}\\n.dw-mega-header,.dw-mega-content-wrap,.dw-mega-hub{display:none}\\n\\n/* Language toggle */\\n.dw-lang-toggle{display:flex;align-items:center;gap:6px;margin-left:16px;font-family:\'Noto Sans\', sans-serif;font-size:13px;font-weight:600}\\n.dw-lang-option{color:#000864;text-decoration:none;padding:4px 6px;border-radius:4px;transition:all 0.3s ease;opacity:0.5;min-width:44px;min-height:44px;display:inline-flex;align-items:center;justify-content:center}\\n.dw-lang-option:hover{opacity:0.8}\\n.dw-lang-option.active{opacity:1;color:#0284c7}\\n.dw-lang-sep{color:rgba(37,59,80,0.3);font-weight:400;user-select:none}\\n\\n/* CTA button */\\n.dw-header-cta{font-family:\'Noto Sans\', sans-serif;font-size:15px;font-weight:600;background:linear-gradient(135deg, #00AFF0 0%, #0284c7 100%);color:#ffffff !important;padding:15px 28px;border-radius:10px;text-decoration:none;transition:all 0.3s cubic-bezier(0.4, 0, 0.2, 1);box-shadow:0 4px 15px rgba(0,175,240,0.3);position:relative;overflow:hidden;display:inline-flex}\\n.dw-header-cta::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s ease}\\n.dw-header-cta:hover::before{left:100%}\\n.dw-header-cta:hover{transform:translateY(-2px);box-shadow:0 8px 25px rgba(0,175,240,0.4)}\\n\\n/* Hamburger */\\n.dw-menu-toggle{display:none;flex-direction:column;gap:5px;cursor:pointer;padding:12px;background:none;border:none;position:static;z-index:auto;min-width:48px;min-height:44px;align-items:center;justify-content:center}\\n.dw-menu-toggle span{width:24px;height:2px;background:#000864;transition:all 0.3s ease}\\n.dw-nav::after{content:none;display:none}\\n\\n/* ===== RESPONSIVE + REDUCED MOTION ===== */\\n/* NOTE: @media rules moved to inline <style> in header HTML. */\\n/* Divi strips @media from _et_pb_custom_css in Theme Builder templates. */\\n/* Header responsive — must be inline (Divi strips @media from _et_pb_custom_css in Theme Builder templates) */\\n/* DIVI BUG DEFENSE: Divi\'s et-critical-inline-css extracts CSS from Code Module <style>\\n   blocks and strips ALL @media wrappers. Mobile-only rules leak to desktop. We combat this\\n   by ensuring EVERY property set in mobile @media has an explicit desktop default in the\\n   non-@media CSS above. Our body <style> comes after et-critical-inline-css in <head>,\\n   so source order lets our desktop defaults win over stripped mobile values. */\\n@media(max-width:1024px){\\n  .dw-header-inner{padding:0 24px;height:70px}\\n  .dw-logo-img--desktop{display:none}\\n  .dw-logo-img--mobile{display:block}\\n  .dw-nav{display:none;position:fixed;top:70px;left:0;width:100%;height:calc(100dvh - 70px);background:#fff;flex-direction:column;overflow-y:auto;padding:8px 0 100px;z-index:999998;box-shadow:0 8px 32px rgba(37,59,80,0.15)}\\n  .dw-nav.dw-nav--open{display:flex}\\n  .dw-nav-item{width:100%;border-bottom:1px solid rgba(37,59,80,0.06)}\\n  .dw-nav-link{display:flex;align-items:center;justify-content:space-between;padding:16px 24px;font-size:16px;font-weight:500;color:#000864;width:100%}\\n  .dw-nav-link::after{display:none}\\n  .dw-nav-link svg{width:20px;height:20px;transition:transform 0.3s ease}\\n  .dw-nav-item.active .dw-nav-link svg{transform:rotate(180deg)}\\n  .dw-mega-menu{position:static;opacity:1;visibility:visible;transform:none;display:none;box-shadow:none;border-radius:0;background:#f8fafc;padding:0;width:100%}\\n  .dw-mega-menu.active{display:block}\\n  .dw-mega-menu::before{display:none}\\n  .dw-mega-inner{display:flex;flex-direction:column;padding:8px 0;gap:0}\\n  .dw-mega-column{padding:0;border:none}\\n  .dw-mega-column-title{padding:12px 32px 4px;font-size:11px;letter-spacing:0.08em;text-transform:uppercase;color:#5b6b80}\\n  .dw-mega-item{padding:12px 32px;border-radius:0;gap:12px}\\n  .dw-mega-item:hover{background:rgba(0,175,240,0.06)}\\n  .dw-mega-icon{width:32px;height:32px;min-width:32px}\\n  .dw-mega-title{font-size:14px}\\n  .dw-mega-desc{font-size:12px}\\n  .dw-mega-viewall{padding:12px 32px;border-radius:0;font-size:13px}\\n  .dw-mega-featured{display:none}\\n  .dw-nav::after{content:\'\';display:block;padding:16px 24px}\\n  .dw-menu-toggle{display:flex;position:relative;z-index:999999}\\n  .dw-menu-toggle.active span:nth-child(1){transform:rotate(45deg) translate(5px,5px)}\\n  .dw-menu-toggle.active span:nth-child(2){opacity:0}\\n  .dw-menu-toggle.active span:nth-child(3){transform:rotate(-45deg) translate(5px,-5px)}\\n  .dw-header-cta{display:none}\\n  .dw-lang-toggle{margin-left:auto;margin-right:8px}\\n}\\n@media(prefers-reduced-motion:reduce){\\n  .dw-header,.dw-header-cta,.dw-mega-menu,.dw-nav-link,.dw-nav-link::after,.dw-mega-item,.dw-mega-icon,.dw-mega-featured-cta,.dw-mega-viewall svg,.dw-logo,.dw-logo-since,.dw-menu-toggle span,.dw-nav-link svg,.dw-lang-option{transition:none !important}\\n  .dw-header-cta::before{transition:none !important}\\n  .dw-header-cta:hover,.dw-mega-featured-cta:hover,.dw-logo:hover{transform:none !important}\\n}\\n/* === GLOBAL MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\\n/* Injected via header so it applies to ALL pages without per-page rebuild */\\n@media(max-width:768px){\\n  a:not(.dw-logo):not(.dw-nav-link):not(.dw-mega-item):not(.dw-mega-viewall):not([class*=\\"btn\\"]):not([class*=\\"cta\\"]):not([class*=\\"Cta\\"]){min-height:44px;display:inline-flex;align-items:center}\\n  input:not([type=\\"hidden\\"]):not([type=\\"checkbox\\"]):not([type=\\"radio\\"]),select,textarea{min-height:44px}\\n}\\n</style>\\n<header class=\\"dw-header\\">\\n  <div class=\\"dw-header-inner\\">\\n    <a href=\\"/\\" class=\\"dw-logo\\">\\